  1→interface BookmarkInput {
  2→  url: string;
  3→  title: string | null;
  4→  selection: string | null;
  5→  tags: string[] | null;
  6→  sensitivity: string;
  7→}
  8→
  9→interface CaptureMessage {
 10→  action: "captureBookmark";
 11→  input: BookmarkInput;
 12→}
 13→
 14→interface CaptureResult {
 15→  success: boolean;
 16→  error?: string;
 17→  data?: {
 18→    id: string;
 19→    status: string;
 20→    title: string;
 21→    tags: string[];
 22→  };
 23→}
 24→
 25→interface GraphQLResponse {
 26→  data?: {
 27→    captureBookmark: {
 28→      id: string;
 29→      status: string;
 30→      title: string;
 31→      tags: string[];
 32→    };
 33→  };
 34→  errors?: Array<{
 35→    message: string;
 36→    extensions?: { code?: string };
 37→  }>;
 38→}
 39→
 40→const CAPTURE_MUTATION = `
 41→  mutation CaptureBookmark($input: BookmarkInput!) {
 42→    captureBookmark(input: $input) {
 43→      id
 44→      status
 45→      title
 46→      tags
 47→    }
 48→  }
 49→`;
 50→
 51→chrome.runtime.onMessage.addListener(
 52→  (
 53→    message: CaptureMessage,
 54→    _sender: chrome.runtime.MessageSender,
 55→    sendResponse: (response: CaptureResult) => void,
 56→  ) => {
 57→    if (message.action === "captureBookmark") {
 58→      handleCapture(message.input).then(sendResponse);
 59→      return true; // keep message channel open for async response
 60→    }
 61→  },
 62→);
 63→
 64→async function handleCapture(input: BookmarkInput): Promise<CaptureResult> {
 65→  try {
 66→    const { apiUrl, jwtToken } = await chrome.storage.local.get([
 67→      "apiUrl",
 68→      "jwtToken",
 69→    ]);
 70→
 71→    if (!apiUrl || !jwtToken) {
 72→      return { success: false, error: "Extension not configured" };
 73→    }
 74→
 75→    const graphqlUrl = (apiUrl as string).replace(/\/+$/, "") + "/graphql";
 76→
 77→    const res = await fetch(graphqlUrl, {
 78→      method: "POST",
 79→      headers: {
 80→        "Content-Type": "application/json",
 81→        Authorization: "Bearer " + jwtToken,
 82→      },
 83→      body: JSON.stringify({
 84→        query: CAPTURE_MUTATION,
 85→        variables: { input },
 86→      }),
 87→    });
 88→
 89→    if (!res.ok) {
 90→      if (res.status === 401) {
 91→        return {
 92→          success: false,
 93→          error:
 94→            "Authentication failed — check your token in extension settings",
 95→        };
 96→      }
 97→      const text = await res.text();
 98→      return { success: false, error: `HTTP ${res.status}: ${text}` };
 99→    }
100→
101→    const json: GraphQLResponse = await res.json();
102→
103→    if (json.errors && json.errors.length > 0) {
104→      const authError = json.errors.find(
105→        (e) =>
106→          e.extensions?.code === "UNAUTHENTICATED" ||
107→          e.extensions?.code === "FORBIDDEN",
108→      );
109→      if (authError) {
110→        return {
111→          success: false,
112→          error:
113→            "Authentication failed — check your token in extension settings",
114→        };
115→      }
116→      return { success: false, error: json.errors[0].message };
117→    }
118→
119→    return { success: true, data: json.data!.captureBookmark };
120→  } catch (err) {
121→    return { success: false, error: (err as Error).message };
122→  }
123→}
